Javascript.miscCode:
			SelectOrderDetails.componentName =	"Order details";
			SelectOrderDetails.srcData = 		REF_DATA_XPATH + "/OrderDetailsList";
			SelectOrderDetails.rowXPath = 		"OrderDetail";
			SelectOrderDetails.keyXPath =		"Description";
			
			function SelectOrderDetailsLOVButton() {};
			
			SelectOrderDetailsLOVButton.tabIndex = __tabIdx++;

			function SelectOrderDetailsLOVGrid() {};
			
			SelectOrderDetailsLOVGrid.dataBinding = "/ds/var/page/OracleReportForm/Dummy";
			SelectOrderDetailsLOVGrid.srcData = REF_DATA_XPATH + "/OrderDetailsList";
			SelectOrderDetailsLOVGrid.rowXPath = "OrderDetail";
			SelectOrderDetailsLOVGrid.keyXPath = "Description";
			SelectOrderDetailsLOVGrid.columns = [
				{xpath: "Description"}
			];
			
			SelectOrderDetailsLOVGrid.raise = {
				eventBinding: {
					singleClicks: [ {element: "SelectOrderDetailsLOVButton"} ],
					keys: [ { key: Key.F6, element: "SelectOrderDetails" } ]
				}
			};
			
			function transformPoundSymbol(value)
			{
				//debugger;
				var transformedValue = value;
				if (value.indexOf("£") != -1)
				{
					transformedValue = replaceString(value, "£", "&#65533");
				}
				return transformedValue;
			}
			
			function replaceString(mainStr, searchStr, replaceStr)
			{
				return mainStr.split(searchStr).join(replaceStr);
			}
